int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, W;
        scanf("%d %d %d", &N, &M, &W);
        int X[N], Y[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &X[i], &Y[i]);
        }
        int R[M], C[M];
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &R[i], &C[i]);
        }
        // Create graph
        int graph[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                graph[i][j] = INT_MAX;
            }
        }
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                for (int k = 0; k < N; k++) {
                    if (j != k && (X[j] - X[k]) * (X[j] - X[k]) + (Y[j] - Y[k]) * (Y[j] - Y[k]) <= 4 * R[i] * R[i]) {
                        if(graph[j][k] > C[i]){
                            graph[j][k] = C[i];
                        }
                    }
                }
            }
        }
        // Dijkstra's algorithm
        int dist[N];
        int visited[N];
        for (int i = 0; i < N; i++) {
            dist[i] = INT_MAX;
            visited[i] = 0;
        }
        dist[0] = 0;
        for (int i = 0; i < N; i++) {
            int min_dist = INT_MAX;
            int min_index = -1;
            for (int j = 0; j < N; j++) {
                if (!visited[j] && dist[j] < min_dist) {
                    min_dist = dist[j];
                    min_index = j;
                }
            }
            visited[min_index] = 1;
            for (int j = 0; j < N; j++) {
                if (!visited[j] && graph[min_index][j] != INT_MAX && dist[min_index] + graph[min_index][j] < dist[j]) {
                    dist[j] = dist[min_index] + graph[min_index][j];
                }
            }
        }
        if (dist[N - 1] == INT_MAX) {
            printf("impossible\n");
        } else {
            printf("%d\n", dist[N - 1]);
        }
    }
    return 0;
}

