                            if(graph[j][k] > C[i]){
                                graph[j][k] = C[i];
                            }
                        }
                    }
                }
            }
            // Dijkstra's algorithm
            int[] dist = new int[N];
            boolean[] visited = new boolean[N];
            Arrays.fill(dist, Integer.MAX_VALUE);
            dist[0] = 0;
            for (int i = 0; i < N; i++) {
                int min_dist = Integer.MAX_VALUE;
                int min_index = -1;
                for (int j = 0; j < N; j++) {
                    if (!visited[j] && dist[j] < min_dist) {
                        min_dist = dist[j];
                        min_index = j;
                    }
                }
                visited[min_index] = true;
                for (int j = 0; j < N; j++) {
                    if (!visited[j] && graph[min_index][j] != Integer.MAX_VALUE && dist[min_index] + graph[min_index][j] < dist[j]) {
                        dist[j] = dist[min_index] + graph[min_index][j];
                    }
                }
            }
            if (dist[N - 1] == Integer.MAX_VALUE) {
